// UpdatePlacement implements mm_service.Repository
func (mmUpdatePlacement *RepositoryMock) UpdatePlacement(ctx context.Context, p domain.Placement) (p1 domain.Placement, err error) {
	mm_atomic.AddUint64(&mmUpdatePlacement.beforeUpdatePlacementCounter, 1)
	defer mm_atomic.AddUint64(&mmUpdatePlacement.afterUpdatePlacementCounter, 1)

	mmUpdatePlacement.t.Helper()

	if mmUpdatePlacement.inspectFuncUpdatePlacement != nil {
		mmUpdatePlacement.inspectFuncUpdatePlacement(ctx, p)
	}

	mm_params := RepositoryMockUpdatePlacementParams{ctx, p}

	// Record call args
	mmUpdatePlacement.UpdatePlacementMock.mutex.Lock()
	mmUpdatePlacement.UpdatePlacementMock.callArgs = append(mmUpdatePlacement.UpdatePlacementMock.callArgs, &mm_params)
	mmUpdatePlacement.UpdatePlacementMock.mutex.Unlock()

	for _, e := range mmUpdatePlacement.UpdatePlacementMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.p1, e.results.err
		}
	}

	if mmUpdatePlacement.UpdatePlacementMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.Counter, 1)
		mm_want := mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.params
		mm_want_ptrs := mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.paramPtrs

		mm_got := RepositoryMockUpdatePlacementParams{ctx, p}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.ctx != nil && !minimock.Equal(*mm_want_ptrs.ctx, mm_got.ctx) {
				mmUpdatePlacement.t.Errorf("RepositoryMock.UpdatePlacement got unexpected parameter ctx, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.expectationOrigins.originCtx, *mm_want_ptrs.ctx, mm_got.ctx, minimock.Diff(*mm_want_ptrs.ctx, mm_got.ctx))
			}

			if mm_want_ptrs.p != nil && !minimock.Equal(*mm_want_ptrs.p, mm_got.p) {
				mmUpdatePlacement.t.Errorf("RepositoryMock.UpdatePlacement got unexpected parameter p, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.expectationOrigins.originP, *mm_want_ptrs.p, mm_got.p, minimock.Diff(*mm_want_ptrs.p, mm_got.p))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmUpdatePlacement.t.Errorf("RepositoryMock.UpdatePlacement got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmUpdatePlacement.UpdatePlacementMock.defaultExpectation.results
		if mm_results == nil {
			mmUpdatePlacement.t.Fatal("No results are set for the RepositoryMock.UpdatePlacement")
		}
		return (*mm_results).p1, (*mm_results).err
	}
	if mmUpdatePlacement.funcUpdatePlacement != nil {
		return mmUpdatePlacement.funcUpdatePlacement(ctx, p)
	}
	mmUpdatePlacement.t.Fatalf("Unexpected call to RepositoryMock.UpdatePlacement. %v %v", ctx, p)
	return
}

// UpdatePlacementAfterCounter returns a count of finished RepositoryMock.UpdatePlacement invocations
func (mmUpdatePlacement *RepositoryMock) UpdatePlacementAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmUpdatePlacement.afterUpdatePlacementCounter)
}

// UpdatePlacementBeforeCounter returns a count of RepositoryMock.UpdatePlacement invocations
func (mmUpdatePlacement *RepositoryMock) UpdatePlacementBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmUpdatePlacement.beforeUpdatePlacementCounter)
}

// Calls returns a list of arguments used in each call to RepositoryMock.UpdatePlacement.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmUpdatePlacement *mRepositoryMockUpdatePlacement) Calls() []*RepositoryMockUpdatePlacementParams {
	mmUpdatePlacement.mutex.RLock()

	argCopy := make([]*RepositoryMockUpdatePlacementParams, len(mmUpdatePlacement.callArgs))
	copy(argCopy, mmUpdatePlacement.callArgs)

	mmUpdatePlacement.mutex.RUnlock()

	return argCopy
}

// MinimockUpdatePlacementDone returns true if the count of the UpdatePlacement invocations corresponds
// the number of defined expectations
func (m *RepositoryMock) MinimockUpdatePlacementDone() bool {
	if m.UpdatePlacementMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.UpdatePlacementMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.UpdatePlacementMock.invocationsDone()
}

// MinimockUpdatePlacementInspect logs each unmet expectation
func (m *RepositoryMock) MinimockUpdatePlacementInspect() {
	for _, e := range m.UpdatePlacementMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to RepositoryMock.UpdatePlacement at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterUpdatePlacementCounter := mm_atomic.LoadUint64(&m.afterUpdatePlacementCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.UpdatePlacementMock.defaultExpectation != nil && afterUpdatePlacementCounter < 1 {
		if m.UpdatePlacementMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to RepositoryMock.UpdatePlacement at\n%s", m.UpdatePlacementMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to RepositoryMock.UpdatePlacement at\n%s with params: %#v", m.UpdatePlacementMock.defaultExpectation.expectationOrigins.origin, *m.UpdatePlacementMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcUpdatePlacement != nil && afterUpdatePlacementCounter < 1 {
		m.t.Errorf("Expected call to RepositoryMock.UpdatePlacement at\n%s", m.funcUpdatePlacementOrigin)
	}

	if !m.UpdatePlacementMock.invocationsDone() && afterUpdatePlacementCounter > 0 {
		m.t.Errorf("Expected %d calls to RepositoryMock.UpdatePlacement at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.UpdatePlacementMock.expectedInvocations), m.UpdatePlacementMock.expectedInvocationsOrigin, afterUpdatePlacementCounter)
	}
}

